code = """import json, re
# Load saved results
path_univ = var_call_5hfOOzVekj2vU7HdE07OAzBp
path_citing = var_call_ve2g86unmpIwbOrX6CUCNLSm
with open(path_univ, 'r', encoding='utf-8') as f:
    univ_data = json.load(f)
with open(path_citing, 'r', encoding='utf-8') as f:
    citing_data = json.load(f)

pat = re.compile(r"\b[A-Z]{2}-[0-9A-Z\-]{4,}\b")
# gather publication numbers for UNIV CALIFORNIA
univ_pub_nums = set()
for rec in univ_data:
    pi = rec.get('Patents_info','')
    if 'UNIV CALIFORNIA' in pi.upper():
        for m in pat.findall(pi):
            univ_pub_nums.add(m)

# build mapping from assignee -> set of primary CPC codes
assignee_map = {}
assignee_pat = re.compile(r"^(.*?)(?:\s+(?:holds|has|is assigned to|assigned to|is owned by|owns|is held by|is the owner of|owned by|is assigned|assigned)\b)", re.IGNORECASE)

for rec in citing_data:
    cit_raw = rec.get('citation','')
    try:
        citlist = json.loads(cit_raw)
    except Exception:
        citlist = []
    cites_univ = False
    for c in citlist:
        pn = c.get('publication_number','')
        if pn and pn in univ_pub_nums:
            cites_univ = True
            break
    if not cites_univ:
        # check substring match
        for pn in list(univ_pub_nums)[:1000]:
            if pn and pn in cit_raw:
                cites_univ = True
                break
    if not cites_univ:
        continue
    # extract assignee
    pi = rec.get('Patents_info','')
    m = assignee_pat.search(pi)
    if m:
        assignee = m.group(1).strip()
    else:
        # fallback: take up to first comma
        assignee = pi.split(',')[0].strip()
    if not assignee:
        assignee = 'UNKNOWN'
    if 'UNIV CALIFORNIA' in assignee.upper():
        continue
    # extract primary cpc
    primary = None
    cpc_field = rec.get('cpc','')
    try:
        cpcs = json.loads(cpc_field)
        if isinstance(cpcs, list):
            for e in cpcs:
                if isinstance(e, dict) and e.get('first'):
                    primary = e.get('code')
                    break
            if not primary and len(cpcs)>0 and isinstance(cpcs[0], dict):
                primary = cpcs[0].get('code')
    except Exception:
        # regex fallback
        m2 = pat.search(cpc_field)
        if m2:
            primary = m2.group(0)
    if not primary:
        primary = 'UNKNOWN'
    assignee_map.setdefault(assignee, set()).add(primary)

# prepare output lists
assignee_map_json = {k: sorted(list(v)) for k,v in assignee_map.items()}
all_cpcs = sorted({code for s in assignee_map_json.values() for code in s if code and code!='UNKNOWN'})

out = {'assignee_map': assignee_map_json, 'cpc_codes': all_cpcs}
print('__RESULT__:')
print(json.dumps(out))"""

